import React, { useEffect } from "react";

const SplashScreen = ({ onComplete }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onComplete();
    }, 2000); // Match animation duration

    return () => clearTimeout(timer);
  }, [onComplete]);

  return (
    <div className="fixed inset-0 bg-[#0f172a] flex justify-center items-center z-50">
      <h1 className="text-4xl md:text-6xl font-extrabold text-cyan-300 tracking-widest animate-riseFadeOut">
        NEURAL NINJAS'S
      </h1>
    </div>
  );
};

export default SplashScreen;
